3139 /// Get values V_i such that V uge V_i (GreaterEq) or V ule V_i (LowerEq).
3140 static void getUnsignedMonotonicValues(SmallPtrSetImpl<Value *> &Res, Value *V,
3141                                        MonotonicType Type,
3142                                        const SimplifyQuery &Q,
3143                                        unsigned Depth = 0) {
3144   if (!Res.insert(V).second)
3145     return;
3146 
3147   // Can be increased if useful.
3148   if (++Depth > 1)
3149     return;
3150 
3151   auto *I = dyn_cast<Instruction>(V);
3152   if (!I)
3153     return;
3154 
3155   Value *X, *Y;
3156   if (Type == MonotonicType::GreaterEq) {
3157     if (match(I, m_Or(m_Value(X), m_Value(Y))) ||
3158         match(I, m_Intrinsic<Intrinsic::uadd_sat>(m_Value(X), m_Value(Y)))) {
3159       getUnsignedMonotonicValues(Res, X, Type, Q, Depth);
3160       getUnsignedMonotonicValues(Res, Y, Type, Q, Depth);
3161     }
3162     // X * Y >= X --> true
3163     if (match(I, m_NUWMul(m_Value(X), m_Value(Y)))) {
3164       if (isKnownNonZero(X, Q))
3165         getUnsignedMonotonicValues(Res, Y, Type, Q, Depth);
3166       if (isKnownNonZero(Y, Q))
3167         getUnsignedMonotonicValues(Res, X, Type, Q, Depth);
3168     }
3169   } else {
3170     assert(Type == MonotonicType::LowerEq);
3171     switch (I->getOpcode()) {
3172     case Instruction::And:
3173       getUnsignedMonotonicValues(Res, I->getOperand(0), Type, Q, Depth);
3174       getUnsignedMonotonicValues(Res, I->getOperand(1), Type, Q, Depth);
3175       break;
3176     case Instruction::URem:
3177     case Instruction::UDiv:
3178     case Instruction::LShr:
3179       getUnsignedMonotonicValues(Res, I->getOperand(0), Type, Q, Depth);
3180       break;
3181     case Instruction::Call:
3182       if (match(I, m_Intrinsic<Intrinsic::usub_sat>(m_Value(X))))
3183         getUnsignedMonotonicValues(Res, X, Type, Q, Depth);
3184       break;
3185     default:
3186       break;
3187     }
3188   }
3189 }
